package com.example.patientsymptomprescreener.data.repository

import com.example.patientsymptomprescreener.data.model.AnalysisRequest
import com.example.patientsymptomprescreener.data.model.AnalysisResponse
import com.example.patientsymptomprescreener.network.ApiService

class SymptomRepository {

    suspend fun analyze(request: AnalysisRequest): Result<AnalysisResponse> {
        return try {
            val response = ApiService.analyze(request)
            Result.success(response)
        } catch (e: Exception) {
            Result.failure(e)
        }
    }
}

