package com.example.patientsymptomprescreener.network

import com.example.patientsymptomprescreener.data.model.AnalysisRequest
import com.example.patientsymptomprescreener.data.model.AnalysisResponse
import io.ktor.client.*
import io.ktor.client.call.*
import io.ktor.client.engine.okhttp.*
import io.ktor.client.plugins.contentnegotiation.*
import io.ktor.client.plugins.logging.*
import io.ktor.client.request.*
import io.ktor.http.*
import io.ktor.serialization.kotlinx.json.*
import kotlinx.serialization.json.Json

/**
 * ApiService wraps the Ktor HTTP client.
 *
 * BASE_URL points to the Ktor backend middleware (see /backend/).
 * The middleware holds the Gemini API key so it never lives on-device.
 *
 * For local development:
 *   - Android Emulator  → http://10.0.2.2:8080
 *   - Physical device   → http://<your-machine-ip>:8080
 * For production, replace with your deployed backend URL (HTTPS).
 */
object ApiService {

    private const val BASE_URL = "http://10.0.2.2:8080" // ← change for production

    private val json = Json {
        ignoreUnknownKeys = true
        isLenient = true
    }

    val client = HttpClient(OkHttp) {
        install(ContentNegotiation) {
            json(json)
        }
        install(Logging) {
            logger = Logger.ANDROID
            level = LogLevel.BODY
        }
        engine {
            config {
                // Enforce TLS for non-localhost connections (NFR-01)
                followRedirects(true)
            }
        }
    }

    suspend fun analyze(request: AnalysisRequest): AnalysisResponse {
        return client.post("$BASE_URL/analyze") {
            contentType(ContentType.Application.Json)
            setBody(request)
        }.body()
    }
}

