package com.prescreener.backend.config

import java.io.File
import java.util.*

/**
 * Centralized configuration manager for the backend.
 * Reads settings from:
 * 1. local.properties (primary - development/CI)
 * 2. System environment variables (fallback - production/Docker)
 * 3. application.conf (optional - future extension)
 */
object ConfigManager {
    private val properties = Properties()

    init {
        // Try to load local.properties from project root
        val localPropsFile = File("../../local.properties")
        if (localPropsFile.exists()) {
            properties.load(localPropsFile.inputStream())
            println("[CONFIG] Loaded local.properties from: ${localPropsFile.absolutePath}")
        } else {
            println("[CONFIG] local.properties not found at ${localPropsFile.absolutePath} (optional for non-dev environments)")
        }
    }

    /**
     * Get a configuration value from local.properties or environment variable.
     * Preference order:
     * 1. Environment variable (overrides all)
     * 2. local.properties value
     * 3. Default value (if provided)
     */
    fun getString(key: String, default: String? = null): String? {
        // Check environment first (allows overrides)
        val envValue = System.getenv(key)
        if (envValue != null && envValue.isNotBlank()) {
            return envValue
        }

        // Check properties file
        val propsValue = properties.getProperty(key)
        if (propsValue != null && propsValue.isNotBlank()) {
            return propsValue
        }

        // Return default
        return default
    }

    /**
     * Get a configuration value and throw if not found.
     */
    fun getStringRequired(key: String): String {
        val value = getString(key)
        if (value.isNullOrBlank()) {
            throw IllegalStateException(
                "Required configuration key '$key' not found. " +
                "Please set it in local.properties or as environment variable '$key'."
            )
        }
        return value
    }

    fun getInt(key: String, default: Int = 8080): Int {
        return getString(key)?.toIntOrNull() ?: default
    }

    fun getBoolean(key: String, default: Boolean = false): Boolean {
        return getString(key)?.toBoolean() ?: default
    }
}

package com.prescreener.backend.plugins

import com.prescreener.backend.model.*
import io.ktor.client.*
import io.ktor.client.call.*
import io.ktor.client.call.*
import io.ktor.client.engine.okhttp.*
import io.ktor.client.plugins.contentnegotiation.*
import io.ktor.client.request.*
import io.ktor.http.*
import io.ktor.serialization.kotlinx.json.*
import io.ktor.server.application.*
import io.ktor.server.request.*
import io.ktor.server.response.*
import io.ktor.server.routing.*
private const val GEMINI_MODEL = "gemini-1.5-flash"  // fast + cost-efficient; swap to gemini-1.5-pro for higher quality
private val GEMINI_URL get() =
    "https://generativelanguage.googleapis.com/v1beta/models/$GEMINI_MODEL:generateContent?key=$GEMINI_API_KEY"

// ─── HTTP client (reused across requests) ───────────────────────────────────
private val httpClient = HttpClient(OkHttp) {
    install(ContentNegotiation) {
        json(Json { ignoreUnknownKeys = true; isLenient = true })
    }
}

// ─── System Prompt (Prompt Engineering per design doc) ──────────────────────
private val SYSTEM_PROMPT = """
You are a medical triage assistant helping clinical staff prioritize patient care.

Respond ONLY in valid JSON format with exactly these keys:
- "possible_categories": array of strings (3–5 possible medical categories, most likely first)
- "urgency_level": exactly one of "Immediate", "Urgent", "Semi-Urgent", or "Non-Urgent"
- "doctor_note": string, max 100 words, a concise clinical summary with recommended actions

Do not add any text, explanation, or markdown outside the JSON object.
""".trimIndent()

// ─── User Prompt Builder ─────────────────────────────────────────────────────
private fun buildUserPrompt(req: AnalysisRequest): String = """
Patient: ${req.age} year old ${req.sex}.
Known conditions: ${req.conditions}.
Allergies: ${req.allergies}.
Symptoms reported: ${req.symptomText}.
Quick-select tags: ${if (req.tags.isEmpty()) "None selected" else req.tags.joinToString(", ")}.
""".trimIndent()

fun Application.configureRouting() {
    routing {

        // Health check
        get("/health") {
            call.respondText("Patient Pre-Screener backend is running ✓")
        }

        // ── Main AI Endpoint ─────────────────────────────────────────────────
        post("/analyze") {
            val request = call.receive<AnalysisRequest>()

            val geminiRequest = GeminiRequest(
                contents = listOf(
                    GeminiContent(
                        role = "user",
                        parts = listOf(GeminiPart(text = buildUserPrompt(request)))
                    )
                ),
                systemInstruction = GeminiContent(
                    parts = listOf(GeminiPart(text = SYSTEM_PROMPT))
                ),
                generationConfig = GenerationConfig(responseMimeType = "application/json")
            )

            try {
                val geminiResponse: GeminiResponse = httpClient.post(GEMINI_URL) {
                    contentType(ContentType.Application.Json)
                    setBody(geminiRequest)
                }.body()

                val rawText = geminiResponse.candidates
                    .firstOrNull()
                    ?.content?.parts?.firstOrNull()?.text
                    ?: throw IllegalStateException("Empty response from Gemini")
            """.trimIndent()

                // Parse the JSON string Gemini returned
                val jsonElement = Json.parseToJsonElement(rawText).jsonObject
                contents = listOf(Content(parts = listOf(Part(text = prompt))))
            )

                val response = AnalysisResponse(
                    possibleCategories = jsonElement["possible_categories"]
                        ?.jsonArray?.map { it.jsonPrimitive.content }
                        ?: listOf("Unable to determine"),
                    urgencyLevel = jsonElement["urgency_level"]?.jsonPrimitive?.content
                        ?: "Unknown",
                    doctorNote = jsonElement["doctor_note"]?.jsonPrimitive?.content
                        ?: "Unable to generate note."
                )

                call.respond(HttpStatusCode.OK, response)

            } catch (e: Exception) {
                call.respond(
                    HttpStatusCode.InternalServerError,
                    mapOf("error" to (e.message ?: "Unknown error calling Gemini API"))
                )
            }
        }
    }
}

package com.prescreener.backend.plugins

import com.prescreener.backend.config.ConfigManager
import com.prescreener.backend.model.*
import io.ktor.client.*
import io.ktor.client.call.*
import io.ktor.client.engine.okhttp.*
import io.ktor.client.plugins.contentnegotiation.*
import io.ktor.client.request.*
import io.ktor.client.statement.*
import io.ktor.http.*
import io.ktor.serialization.kotlinx.json.*
import io.ktor.server.application.*
import io.ktor.server.request.*
import io.ktor.server.response.*
import io.ktor.server.routing.*
import kotlinx.serialization.json.Json

fun Application.configureRouting() {
    // Load Gemini API key from config (local.properties or environment)
    val geminiApiKey = try {
        ConfigManager.getStringRequired("GEMINI_API_KEY")
    } catch (e: IllegalStateException) {
        println("[ERROR] ${e.message}")
        // Still set up routing, but /analyze will fail with a clear error
        ""
    }

    if (geminiApiKey.isNotBlank()) {
        println("[CONFIG] ✓ Gemini API key loaded successfully (${geminiApiKey.take(10)}...)")
    } else {
        println("[WARNING] Gemini API key not configured. /analyze endpoint will return error.")
    }

    val client = HttpClient(OkHttp) {
        install(ContentNegotiation) {
            json(Json { ignoreUnknownKeys = true; isLenient = true })
        }
    }

    routing {
        get("/health") {
            call.respondText("Patient Pre-Screener backend is running ✓")
        }

        post("/analyze") {
            val req = call.receive<AnalysisRequest>()

            if (geminiApiKey.isBlank()) {
                val errorMsg = "Gemini API key is not configured on the server. " +
                    "Please set GEMINI_API_KEY in local.properties or as an environment variable."
                println("[ERROR] /analyze called without API key: $errorMsg")
                call.respond(HttpStatusCode.InternalServerError, mapOf(
                    "error" to "API Configuration Error",
                    "details" to errorMsg,
                    "hint" to "Set GEMINI_API_KEY environment variable or in local.properties"
                ))
                return@post
            }

            val geminiUrl = "https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=$geminiApiKey"

            val prompt = """
                You are a medical triage assistant. Analyze the following patient data:
                Age: ${req.age}
                Sex: ${req.sex}
                Conditions: ${req.conditions}
                Allergies: ${req.allergies}
                Symptom Description: ${req.symptomText}
                Symptoms Tags: ${req.tags.joinToString(", ")}

                Respond with a JSON object containing:
                1. "possibleCategories": A list of 3-5 potential medical areas (e.g., "Cardiology", "Gastroenterology").
                2. "urgencyLevel": One of "IMMEDIATE", "URGENT", "SEMI-URGENT", or "NON-URGENT".
                3. "doctorNote": A brief clinical summary and suggested next steps for triage staff.

                Strictly follow the JSON format. Do not include markdown formatting or extra text.
            """.trimIndent()

            val geminiRequest = GeminiRequest(
                contents = listOf(Content(parts = listOf(Part(text = prompt))))
            )

            try {
                val response: HttpResponse = client.post(geminiUrl) {
                    contentType(ContentType.Application.Json)
                    setBody(geminiRequest)
                }

                if (response.status != HttpStatusCode.OK) {
                    val errorBody = response.bodyAsText()
                    call.respond(HttpStatusCode.InternalServerError, mapOf("error" to "Gemini API error", "details" to errorBody))
                    return@post
                }

                val geminiResponse = response.body<GeminiResponse>()
                val jsonString = geminiResponse.candidates.firstOrNull()?.content?.parts?.firstOrNull()?.text
                    ?: throw Exception("Empty response from Gemini")

                // Gemini sometimes wraps JSON in code blocks
                val cleanJson = jsonString.trim().removeSurrounding("```json", "```").trim()
                val analysis = Json.decodeFromString<AnalysisResponse>(cleanJson)

                call.respond(analysis)
            } catch (e: Exception) {
                call.respond(HttpStatusCode.InternalServerError, mapOf("error" to "Failed to process analysis", "message" to e.message.toString()))
            }
        }
    }
}

package com.prescreener.backend.plugins


import io.ktor.serialization.kotlinx.json.*
import io.ktor.server.application.*
import io.ktor.server.plugins.contentnegotiation.*
import kotlinx.serialization.json.Json

fun Application.configureSerialization() {
    install(ContentNegotiation) {
        json(Json {
            prettyPrint = true
            isLenient = true
            ignoreUnknownKeys = true
        })
    }
}

